1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	export type Step = { op: "quote"; items: Item[] };
3	export type Result = { premium: number };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	const CURSE_RATE = 0.5;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	const HIGH_ENCHANTMENT_RATE = 0.3;
10	
11	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
21	
22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	const COMPONENT_BLOCK_SIZE = 3;
24	const COMPONENT_BLOCK_PRICE = 60;
25	const COMPONENT_UNIT_PRICE = 25;
26	
27	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
28	
29	const roundPremium = (amount: number): number => Math.ceil(amount);
30	
31	const priceForComponentCount = (count: number): number =>
32	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : count * COMPONENT_UNIT_PRICE;
33	
34	const sumComponentBase = (componentCountsByType: Map<string, number>): number => {
35	  let total = 0;
36	  for (const count of componentCountsByType.values()) {
37	    total += priceForComponentCount(count);
38	  }
39	  return total;
40	};
41	
42	const baseForItems = (items: Item[]): number => {
43	  const componentCountsByType = new Map<string, number>();
44	  let nonComponentBase = 0;
45	  for (const item of items) {
46	    if (isComponent(item)) {
47	      componentCountsByType.set(item.type, (componentCountsByType.get(item.type) ?? 0) + 1);
48	    } else {
49	      nonComponentBase += basePremiumFor(item);
50	    }
51	  }
52	  return nonComponentBase + sumComponentBase(componentCountsByType);
53	};
54	
55	const curseSurchargeFor = (item: Item): number =>
56	  item.cursed ? basePremiumFor(item) * CURSE_RATE : 0;
57	
58	const highEnchantmentSurchargeFor = (item: Item): number =>
59	  item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
60	    ? basePremiumFor(item) * HIGH_ENCHANTMENT_RATE
61	    : 0;
62	
63	const PER_ITEM_MODIFIERS: ReadonlyArray<(item: Item) => number> = [
64	  curseSurchargeFor,
65	  highEnchantmentSurchargeFor,
66	];
67	
68	const modifiersForItem = (item: Item): number =>
69	  PER_ITEM_MODIFIERS.reduce((sum, modifier) => sum + modifier(item), 0);
70	
71	const itemModifiersFor = (items: Item[]): number =>
72	  items.reduce((sum, item) => sum + modifiersForItem(item), 0);
73	
74	const quotePremium = (items: Item[]): number => {
75	  const base = baseForItems(items);
76	  const itemModifiers = itemModifiersFor(items);
77	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
78	  return roundPremium(base + itemModifiers + firstInsuranceSurcharge + PROCESSING_FEE);
79	};
80	
81	export const runScenario = (input: {
82	  customer: { yearsWithMHPCO: number };
83	  steps: Step[];
84	}): { results: Result[] } => {
85	  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
86	  return { results };
87	};
